"use client";
import { useGoogleLogin } from "@react-oauth/google";
import { useAuth } from "@/context/AuthContext";
import { useState } from "react";
import { getErrorMessage } from "@/utils/errorHandler";
import { useRouter } from "next/navigation";

interface GoogleLoginButtonProps {
  mode: "login" | "signup";
}

function GoogleLoginButtonInner({ mode }: GoogleLoginButtonProps) {
  const { loginWithGoogle } = useAuth();
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  const handleGoogleLogin = useGoogleLogin({
    onSuccess: async (tokenResponse) => {
      setError("");
      setLoading(true);
      try {
        // Exchange access token for id_token via userinfo
        const userInfo = await fetch("https://www.googleapis.com/oauth2/v3/userinfo", {
          headers: { Authorization: `Bearer ${tokenResponse.access_token}` },
        });
        if (!userInfo.ok) throw new Error("Failed to fetch Google user info.");
        // Use the access token directly as the credential
        await loginWithGoogle(tokenResponse.access_token);
        router.push("/wallet");
      } catch (err: any) {
        console.error("Google Auth Error:", err.response?.data || err.message);
        setError(getErrorMessage(err));
      } finally {
        setLoading(false);
      }
    },
    onError: () => setError("Google Login Failed. Please try again."),
    flow: "implicit",
  });

  return (
    <div className="w-full flex flex-col items-center gap-2">
      <button
        type="button"
        onClick={() => handleGoogleLogin()}
        disabled={loading}
        className="w-full flex items-center justify-center gap-3 bg-white border border-gray-300 rounded-lg px-4 py-3 text-sm font-medium text-gray-700 hover:bg-gray-50 active:bg-gray-100 transition-colors shadow-sm disabled:opacity-60 disabled:cursor-not-allowed"
      >
        {loading ? (
          <div className="w-5 h-5 border-2 border-gray-400 border-t-transparent rounded-full animate-spin" />
        ) : (
          <svg width="20" height="20" viewBox="0 0 48 48" xmlns="http://www.w3.org/2000/svg">
            <path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/>
            <path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/>
            <path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/>
            <path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.18 1.48-4.97 2.31-8.16 2.31-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/>
            <path fill="none" d="M0 0h48v48H0z"/>
          </svg>
        )}
        <span>{loading ? "Signing in..." : mode === "login" ? "Continue with Google" : "Sign up with Google"}</span>
      </button>
      {error && (
        <div className="text-red-500 text-xs text-center bg-red-50 border border-red-100 rounded-lg px-3 py-2 w-full">
          {error}
        </div>
      )}
    </div>
  );
}

export default function GoogleLoginButton({ mode }: GoogleLoginButtonProps) {
  if (!process.env.NEXT_PUBLIC_GOOGLE_CLIENT_ID) return null;
  return <GoogleLoginButtonInner mode={mode} />;
}
